mapper.select:
select *
from event_outbox

  status = #{status}

order by created_at desc, id desc
limit #{limit} offset #{offset}

mapper.update:
update event_outbox
set status = 'processing', attempts = attempts + 1, updated_at = current_timestamp
where id = #{eventId}

update event_outbox
set status = 'sent', sent_at = current_timestamp, error_message = null, updated_at = current_timestamp
where id = #{eventId}

update event_outbox
set status = 'failed', error_message = #{errorMessage}, updated_at = current_timestamp
where id = #{eventId}
